#include <iostream>

using namespace std;

class Animal
{
public:
    virtual void makeSound()
    {
        cout << "Some generic animal sound" << endl;
    }
};

class Dog : public Animal
{
public:
    void makeSound() override
    {
        cout << "Woof!" << endl;
    }
};

int main()
{
    Animal *a = new Dog(); // an Animal pointer, but pointing at an actual Dog

    a->makeSound(); // which version runs?

    delete a;

    return 0;
}

